import { z } from 'zod';

export const createCourseSchema = z.object({
  body: z.object({
    name: z.string().min(2, 'Course name is required'),
    code: z.string().min(2, 'Course code is too short'),
    license_category_id: z.string().optional(),
    system_course_code: z.string().optional(),
    start_date: z.preprocess((arg) => (arg === '' ? undefined : arg), z.coerce.date().optional()),
    end_date: z.preprocess((arg) => (arg === '' ? undefined : arg), z.coerce.date().optional()),
    status: z.enum(['draft', 'ongoing', 'completed', 'canceled']).optional(),
    course_fee: z.number().min(0).optional(),
    description: z.string().optional(),
    note: z.string().optional(),
    course_type: z.string().optional(),
    max_students: z.number().min(0).optional(),
    fee_stages: z
      .array(
        z.object({
          name: z.string(),
          amount: z.number().min(0),
        }),
      )
      .optional(),
  }),
});

export const updateCourseSchema = z.object({
  params: z.object({
    id: z.string().regex(/^[0-9a-fA-F]{24}$/, 'Invalid Course ID format'),
  }),
  body: z.object({
    name: z.string().min(2).optional(),
    code: z.string().min(2).optional(),
    license_category_id: z.string().optional(),
    start_date: z.preprocess((arg) => (arg === '' ? undefined : arg), z.coerce.date().optional()),
    end_date: z.preprocess((arg) => (arg === '' ? undefined : arg), z.coerce.date().optional()),
    status: z.enum(['draft', 'ongoing', 'completed', 'canceled']).optional(),
    course_fee: z.number().min(0).optional(),
    description: z.string().optional(),
    note: z.string().optional(),
    course_type: z.string().optional(),
    max_students: z.number().min(0).optional(),
    fee_stages: z
      .array(
        z.object({
          name: z.string(),
          amount: z.number().min(0),
        }),
      )
      .optional(),
  }),
});

import { z } from 'zod';

export const createStudentSchema = z.object({
  body: z
    .object({
      // User fields (for atomic creation)
      first_name: z.string().min(1, 'First name is required').optional(),
      last_name: z.string().optional(),
      phone: z.string().min(10, 'Phone must be at least 10 digits').optional(),
      email: z.string().email('Invalid email').optional(),
      identity_card: z.string().optional(),
      dob: z.string().optional(),
      address: z.string().optional(),

      // Existing Student fields
      user_id: z.string().optional(),
      region_id: z.string().optional().nullable(),
      course_id: z.string().optional().nullable(),
      enrollment_date: z.string().datetime().optional(),
      status: z.enum(['active', 'completed', 'dropped', 'deferred']).optional(),
      status_detail: z.string().optional(),
      license_category_id: z.string().optional(),
      lead_manager: z.string().optional().nullable(),
    })
    .refine((data) => data.user_id || (data.first_name && data.phone), {
      message: 'Either user_id or (first_name and phone) must be provided',
      path: ['user_id'],
    }),
});

export const updateStudentSchema = z.object({
  params: z.object({
    id: z.string().min(1, 'Student ID is required'),
  }),
  body: z
    .object({
      region_id: z.string().optional().nullable(),
      status: z.enum(['active', 'completed', 'dropped', 'deferred']).optional(),
      enrollment_date: z.string().datetime().optional(),
      student_status_detail: z.record(z.string(), z.any()).optional(),
      health_check_status: z.string().optional(),
      health_check_date: z.string().optional(),
      hospital_id: z.string().optional(),
      health_check_note: z.string().optional(),
      theory_completed: z.boolean().optional(),
      sand_yard_completed: z.boolean().optional(),
      simulation_completed: z.boolean().optional(),
      dat_completed: z.boolean().optional(),
      cabin_completed: z.boolean().optional(),
      lead_manager: z.string().optional().nullable(),
    })
    .partial(),
});

