import express from 'express';
import {
  getAllPayments,
  getPaymentStats,
  getPaymentsByStudent,
  createPayment,
  updatePayment,
  deletePayment,
  exportPayments,
  exportPremiumFinancialReport,
  importPayments,
  getImportTemplate,
} from '@/interface/controllers/payment.controller';
import { validate } from '@/interface/middlewares/validation.middleware';
import { paginationMiddleware } from '@/interface/middlewares/pagination.middleware';
import { createPaymentSchema, updatePaymentSchema } from '@/interface/dtos/payment.dto';
import multer from 'multer';

const upload = multer({ dest: 'uploads/' });
const router = express.Router();

router.get('/', paginationMiddleware, getAllPayments);
router.get('/stats', getPaymentStats);
router.get('/import-template', getImportTemplate);
router.get('/export', exportPayments);
router.get('/export-premium', exportPremiumFinancialReport);
router.get('/student/:studentId', paginationMiddleware, getPaymentsByStudent);
router.post('/', validate(createPaymentSchema), createPayment);
router.post('/import', upload.single('file'), importPayments);
router.put('/:id', validate(updatePaymentSchema), updatePayment);
// Deletion disabled as per requirements: "có thể sửa chứ không thể xoá"
// router.delete('/:id', deletePayment);

export default router;

import { Router } from 'express';
import * as datController from '@/interface/controllers/dat.controller';
import { validate } from '@/interface/middlewares/validation.middleware';
import { createDatSessionSchema } from '@/infrastructure/validation/schemas';

const router = Router();

router.get('/analytics', datController.getDatAnalytics);
router.post('/', validate(createDatSessionSchema), datController.addDatSession);
router.get('/student/:enrollmentId', datController.getStudentDatSessions);

export default router;

import express from 'express';
import * as courseController from '@/interface/controllers/course.controller';
import { validate } from '@/interface/middlewares/validation.middleware';
import { paginationMiddleware } from '@/interface/middlewares/pagination.middleware';
import { createCourseSchema, updateCourseSchema } from '@/interface/dtos/course.dto';
import { bulkUpdateCourseStatusSchema } from '@/infrastructure/validation/schemas';

import multer from 'multer';

const upload = multer({ dest: 'uploads/' });
const router = express.Router();

router.get('/today-milestones', courseController.getTodayMilestones);
router.get('/', paginationMiddleware, courseController.getAllCourses);
router.get('/unassigned', courseController.getUnassignedStudents);
router.get('/stats', courseController.getStats);
router.get('/export', courseController.exportCourses);
router.get('/import-template', courseController.getTemplate);
router.post('/import', upload.single('file'), courseController.importFromExcel);
router.get('/:id', courseController.getCourseById);
router.post('/', validate(createCourseSchema), courseController.createCourse);
router.post('/:id/assign', courseController.assignStudents);
router.put('/:id', validate(updateCourseSchema), courseController.updateCourse);
router.post('/bulk-update-status', validate(bulkUpdateCourseStatusSchema), courseController.bulkUpdateCourseStatus);
router.delete('/:id', courseController.deleteCourse);

export default router;
